+func (a *Analyzer) graphStructureHash() string {
+	if a == nil || a.g == nil {
+		return "none"
+	}
+
+	nodesIt := a.g.Nodes()
+	ids := make([]string, 0, nodesIt.Len())
+	for nodesIt.Next() {
+		id, ok := a.nodeToID[nodesIt.Node().ID()]
+		if ok {
+			ids = append(ids, id)
+		}
+	}
+	sort.Strings(ids)
+
+	type edgeKey struct {
+		from string
+		to   string
+	}
+	edgesIt := a.g.Edges()
+	edges := make([]edgeKey, 0, edgesIt.Len())
+	for edgesIt.Next() {
+		e := edgesIt.Edge()
+		from := a.nodeToID[e.From().ID()]
+		to := a.nodeToID[e.To().ID()]
+		if from == "" || to == "" {
+			continue
+		}
+		edges = append(edges, edgeKey{from: from, to: to})
+	}
+	sort.Slice(edges, func(i, j int) bool {
+		if edges[i].from != edges[j].from {
+			return edges[i].from < edges[j].from
+		}
+		return edges[i].to < edges[j].to
+	})
+
+	edgesDedup := edges[:0]
+	for i := range edges {
+		if i == 0 || edges[i] != edges[i-1] {
+			edgesDedup = append(edgesDedup, edges[i])
+		}
+	}
+
+	h := sha256.New()
+	for _, id := range ids {
+		h.Write([]byte(id))
+		h.Write([]byte{0})
+	}
+	h.Write([]byte{1}) // nodes/edges separator
+	for _, e := range edgesDedup {
+		h.Write([]byte(e.from))
+		h.Write([]byte{0})
+		h.Write([]byte(e.to))
+		h.Write([]byte{0})
+	}
+
+	return hex.EncodeToString(h.Sum(nil))[:16]
+}
